 1	import React, { FC, useEffect, useMemo, useState } from 'react';
 2	
 3	import RedHatProvidedInstanceTypesSection from '@catalog/CreateFromInstanceTypes/components/SelectInstanceTypeSection/components/RedHatProvidedInstanceTypesSection/RedHatProvidedInstanceTypesSection';
 4	import UserProvidedInstanceTypesList from '@catalog/CreateFromInstanceTypes/components/SelectInstanceTypeSection/components/UserProvidedInstanceTypeList/UserProvidedInstanceTypeList';
 5	import { getUserProvidedInstanceTypes } from '@catalog/CreateFromInstanceTypes/components/SelectInstanceTypeSection/components/UserProvidedInstanceTypeList/utils/utils';
 6	import { useInstanceTypeVMStore } from '@catalog/CreateFromInstanceTypes/state/useInstanceTypeVMStore';
 7	import { UseInstanceTypeAndPreferencesValues } from '@catalog/CreateFromInstanceTypes/state/utils/types';
 8	import { getInstanceTypeMenuItems } from '@kubevirt-utils/components/AddBootableVolumeModal/components/VolumeMetadata/components/InstanceTypeDrilldownSelect/utils/utils';
 9	import Loading from '@kubevirt-utils/components/Loading/Loading';
10	import { Tab, Tabs } from '@patternfly/react-core';
11	
12	import { TabKey } from './utils/constants';
13	
14	type SelectInstanceTypeSectionProps = {
15	  instanceTypesAndPreferencesData: UseInstanceTypeAndPreferencesValues;
16	};
17	
18	const SelectInstanceTypeSection: FC<SelectInstanceTypeSectionProps> = ({
19	  instanceTypesAndPreferencesData,
20	}) => {
21	  const [activeTabKey, setActiveTabKey] = useState<TabKey>(TabKey.RedHat);
22	  const { allInstanceTypes, loaded } = instanceTypesAndPreferencesData;
23	
24	  const {
25	    instanceTypeVMState: { selectedInstanceType },
26	  } = useInstanceTypeVMStore();
27	
28	  const menuItems = useMemo(() => getInstanceTypeMenuItems(allInstanceTypes), [allInstanceTypes]);
29	
30	  useEffect(() => {
31	    // This effect is meant to focus the tab an IT was defined as default by the selected volume
32	    const tabToSwitch = menuItems.userProvided.items.includes(selectedInstanceType?.name)
33	      ? TabKey.Users
34	      : TabKey.RedHat;
35	    setActiveTabKey(tabToSwitch);
36	  }, [menuItems.userProvided.items, selectedInstanceType]);
37	
38	  if (!loaded) return <Loading />;
39	
40	  const handleTabClick = (_, tabIndex: TabKey) => {
41	    setActiveTabKey(tabIndex);
42	  };
43	
44	  return (
45	    <Tabs activeKey={activeTabKey} onSelect={handleTabClick}>
46	      <Tab eventKey={TabKey.RedHat} title={menuItems.redHatProvided.label}>
47	        <RedHatProvidedInstanceTypesSection redHatMenuItems={menuItems?.redHatProvided} />
48	      </Tab>
49	      <Tab eventKey={TabKey.Users} title={menuItems.userProvided.label}>
50	        <UserProvidedInstanceTypesList
51	          userProvidedInstanceTypes={getUserProvidedInstanceTypes(allInstanceTypes)}
52	        />
53	      </Tab>
54	    </Tabs>
55	  );
56	};
57	
58	export default SelectInstanceTypeSection;

